import React, { useEffect, useMemo, useState } from 'react';
import { Link } from 'react-router-dom';
import productService from '../services/productService';
import categoryService from '../services/categoryService';

interface LandingProduct {
    id: number;
    name: string;
    brand?: string;
    price: number;
    stock?: number;
    images?: string[] | string | null;
    category_id?: number | string | null;
    category?: {
        id?: number | string;
        name?: string;
        slug?: string;
    } | null;
    vehicle_compatibility?: string | null;
}

interface LandingCategory {
    id: number;
    name: string;
    slug?: string;
}

const formatPeso = (value: number): string => `₱${Number(value || 0).toFixed(2)}`;

export default function Landing() {
    const fallbackProducts = [
        {
            id: 1,
            name: 'Performance Brake Kit',
            brand: 'AKEBONO',
            price: 149.99,
            image: '/images/carvex.png',
        },
        {
            id: 2,
            name: 'Premium LED Headlight Set',
            brand: 'PHILIPS',
            price: 89.99,
            image: '/images/carvex.png',
        },
        {
            id: 3,
            name: 'Steering Wheel Cover Pro',
            brand: 'SPARCO',
            price: 59.99,
            image: '/images/carvex.png',
        },
    ];

    const [products, setProducts] = useState<LandingProduct[]>([]);
    const [categories, setCategories] = useState<LandingCategory[]>([]);
    const [loading, setLoading] = useState(true);
    const [hasError, setHasError] = useState(false);
    const [search, setSearch] = useState('');
    const [categoryId, setCategoryId] = useState('');
    const [priceMax, setPriceMax] = useState(120);
    const [sortBy, setSortBy] = useState('created_at');
    const [sortOrder, setSortOrder] = useState('desc');

    useEffect(() => {
        let isMounted = true;

        const fetchLandingProducts = async () => {
            try {
                setLoading(true);

                const [productResponse, categoryResponse] = await Promise.all([
                    productService.getAll({
                        per_page: 100,
                        sort_by: 'created_at',
                        sort_order: 'desc',
                    }),
                    categoryService.getAll(),
                ]);

                const payload = productResponse?.data?.data;
                const records = Array.isArray(payload?.data)
                    ? payload.data
                    : Array.isArray(payload)
                        ? payload
                        : [];

                const categoryPayload = categoryResponse?.data?.data;
                const categoryRecords = Array.isArray(categoryPayload?.data)
                    ? categoryPayload.data
                    : Array.isArray(categoryPayload)
                        ? categoryPayload
                        : [];

                const normalized = records
                    .filter((item: unknown) => typeof item === 'object' && item !== null)
                    .map((item: Record<string, unknown>) => ({
                        id: Number(item.id || 0),
                        name: String(item.name || ''),
                        brand: String(item.brand || ''),
                        price: Number(item.price || 0),
                        stock: Number(item.stock || 0),
                        images: item.images as string[] | string | null | undefined,
                        category_id: item.category_id as number | string | null | undefined,
                        category: (item.category as LandingProduct['category']) || null,
                        vehicle_compatibility: item.vehicle_compatibility as string | null | undefined,
                    }))
                    .filter((item: LandingProduct) => item.id > 0 && item.name);

                if (isMounted) {
                    setProducts(normalized);
                    setCategories(
                        categoryRecords
                            .filter((item: unknown) => typeof item === 'object' && item !== null)
                            .map((item: Record<string, unknown>) => ({
                                id: Number(item.id || 0),
                                name: String(item.name || ''),
                                slug: String(item.slug || ''),
                            }))
                            .filter((item: LandingCategory) => item.id > 0 && item.name)
                    );
                    setHasError(false);
                }
            } catch (error) {
                if (isMounted) {
                    setHasError(true);
                }
            } finally {
                if (isMounted) {
                    setLoading(false);
                }
            }
        };

        fetchLandingProducts();

        return () => {
            isMounted = false;
        };
    }, []);

    const filteredProducts = useMemo(() => {
        const loweredSearch = search.trim().toLowerCase();
        const selectedCategoryId = String(categoryId || '').trim();

        const nextProducts = products.filter((product) => {
            const categoryValue = String(product.category_id || product.category?.id || '').trim();
            const matchesSearch = !loweredSearch || [product.name, product.brand, product.vehicle_compatibility]
                .filter(Boolean)
                .some((value) => String(value).toLowerCase().includes(loweredSearch));
            const matchesCategory = !selectedCategoryId || categoryValue === selectedCategoryId;

            const matchesPrice = Number(product.price || 0) <= Number(priceMax || 0);

            return matchesSearch && matchesCategory && matchesPrice;
        });

        const sorted = [...nextProducts].sort((left, right) => {
            if (sortBy === 'price') {
                return sortOrder === 'asc'
                    ? Number(left.price || 0) - Number(right.price || 0)
                    : Number(right.price || 0) - Number(left.price || 0);
            }

            if (sortBy === 'name') {
                return sortOrder === 'asc'
                    ? String(left.name || '').localeCompare(String(right.name || ''))
                    : String(right.name || '').localeCompare(String(left.name || ''));
            }

            return sortOrder === 'asc'
                ? Number(left.id || 0) - Number(right.id || 0)
                : Number(right.id || 0) - Number(left.id || 0);
        });

        return sorted.slice(0, 6);
    }, [categoryId, priceMax, products, search, sortBy, sortOrder]);

    const resetFilters = () => {
        setSearch('');
        setCategoryId('');
        setPriceMax(120);
        setSortBy('created_at');
        setSortOrder('desc');
    };

    const displayProducts = useMemo(() => {
        if (filteredProducts.length > 0) {
            return filteredProducts.map((product) => {
                const imageSource = Array.isArray(product.images)
                    ? product.images[0]
                    : product.images;

                return {
                    id: product.id,
                    name: product.name,
                    brand: product.brand || 'CARVEX',
                    price: `P${product.price.toFixed(2)}`,
                    image: imageSource || '/images/carvex.png',
                    to: `/products/${product.id}`,
                };
            });
        }

        return [];
    }, [filteredProducts]);

    const hasVisibleProducts = displayProducts.length > 0;
    const isFilterActive = Boolean(search.trim() || categoryId || Number(priceMax) !== 120 || sortBy !== 'created_at' || sortOrder !== 'desc');

    return (
        <div className="landing-page">
            <section className="landing-hero">
                <div className="landing-content">
                    <span className="landing-kicker">CarVex Automotive Marketplace</span>
                    <h1>Find Trusted Auto Parts Fast</h1>
                    <p>
                        Genuine parts, premium brands, and fast nationwide delivery.
                        Sign in to access your personalized car parts dashboard.
                    </p>
                    <div className="landing-trust-strip" aria-label="Service highlights">
                        <span>Fast shipping</span>
                        <span>Top brands</span>
                        <span>Secure checkout</span>
                    </div>
                    <div className="landing-actions">
                        <Link to="/register" className="btn btn-secondary btn-lg">Get Started</Link>
                        <Link to="/products" className="btn btn-outline-primary btn-lg">Browse Products</Link>
                    </div>
                </div>

                <div className="landing-image-wrap">
                    <img
                        src="/images/carvex.png"
                        alt="CarVex featured automotive visual"
                        className="landing-image"
                    />
                </div>
            </section>

            <section className="landing-shop" aria-labelledby="landing-shop-title">
                <div className="landing-shop-header">
                    <span className="landing-shop-kicker">Shop Preview</span>
                    <h2 id="landing-shop-title">Clean, fast, and built to help you find parts quickly</h2>
                    <p>
                        Explore popular categories and featured items from trusted automotive brands.
                    </p>
                </div>

                <div className="landing-shop-filters" aria-label="Product filters">
                    <div className="landing-shop-filter-group">
                        <label>Search</label>
                        <input
                            type="text"
                            placeholder="Search products..."
                            value={search}
                            onChange={(event) => setSearch(event.target.value)}
                        />
                    </div>

                    <div className="landing-shop-filter-group">
                        <label>Category</label>
                        <select value={categoryId} onChange={(event) => setCategoryId(event.target.value)}>
                            <option value="">All Categories</option>
                            {categories.map((category) => (
                                <option key={category.id} value={category.id}>
                                    {category.name}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div className="landing-shop-filter-group">
                        <label>Price Range</label>
                        <div className="landing-shop-range">
                            <span>{formatPeso(0)}</span>
                            <input
                                type="range"
                                min="0"
                                max="1000"
                                step="1"
                                value={priceMax}
                                onChange={(event) => setPriceMax(Number(event.target.value))}
                            />
                            <span>{formatPeso(priceMax)}</span>
                        </div>
                    </div>

                    <div className="landing-shop-filter-group">
                        <label>Sort By</label>
                        <div className="landing-shop-sort-row">
                            <select value={sortBy} onChange={(event) => setSortBy(event.target.value)}>
                                <option value="created_at">Newest</option>
                                <option value="price">Price</option>
                                <option value="name">Name</option>
                            </select>
                            <select value={sortOrder} onChange={(event) => setSortOrder(event.target.value)}>
                                <option value="desc">Desc</option>
                                <option value="asc">Asc</option>
                            </select>
                        </div>
                    </div>

                    <button type="button" className="btn btn-outline-primary btn-sm" onClick={resetFilters}>
                        Reset Filters
                    </button>
                </div>

                <div className="landing-shop-categories">
                    <Link to="/products" className="landing-category-card">
                        <strong>Brakes</strong>
                        <span>Rotors, pads, kits</span>
                    </Link>
                    <Link to="/products" className="landing-category-card">
                        <strong>Lighting</strong>
                        <span>Headlights, fog lamps</span>
                    </Link>
                    <Link to="/products" className="landing-category-card">
                        <strong>Suspension</strong>
                        <span>Struts, springs, control arms</span>
                    </Link>
                    <Link to="/products" className="landing-category-card">
                        <strong>Engine</strong>
                        <span>Filters, belts, plugs</span>
                    </Link>
                </div>

                <div className="landing-shop-grid">
                    {hasVisibleProducts ? (
                        displayProducts.map((product) => (
                            <article key={product.id} className="landing-shop-card">
                                <div className="landing-shop-card-image">
                                    <img src={product.image} alt={product.name} loading="lazy" />
                                </div>
                                <div className="landing-shop-card-body">
                                    <p className="landing-shop-card-brand">{product.brand}</p>
                                    <h3>{product.name}</h3>
                                    <p className="landing-shop-card-price">{product.price}</p>
                                    <Link to={product.to} className="btn btn-primary btn-sm">
                                        Shop Now
                                    </Link>
                                </div>
                            </article>
                        ))
                    ) : (
                        <div className="landing-shop-empty-state">
                            <strong>No products match your filters.</strong>
                            <p>{isFilterActive ? 'Adjust the search, category, or price settings to see more results.' : 'Products are still loading or unavailable right now.'}</p>
                            {isFilterActive && (
                                <button type="button" className="btn btn-outline-primary btn-sm" onClick={resetFilters}>
                                    Clear Filters
                                </button>
                            )}
                        </div>
                    )}
                </div>

                {loading && <p className="landing-shop-status">Loading latest products...</p>}
                {!loading && hasError && (
                    <p className="landing-shop-status landing-shop-status-error">
                        Showing preview items while products are loading.
                    </p>
                )}
                {!loading && !hasError && !hasVisibleProducts && !isFilterActive && (
                    <p className="landing-shop-status">No products are available right now.</p>
                )}
            </section>
        </div>
    );
}