import api from './api';
import axios, { AxiosRequestConfig } from 'axios';

interface ProductFiltersParams {
    search?: string;
    category?: string;
    brand?: string;
    [key: string]: any;
}

const SUPABASE_URL = String(process.env.MIX_SUPABASE_URL || '').trim();
const SUPABASE_ANON_KEY = String(process.env.MIX_SUPABASE_ANON_KEY || '').trim();
const CAN_USE_SUPABASE = SUPABASE_URL !== '' && SUPABASE_ANON_KEY !== '';

const supabaseRest = axios.create({
    baseURL: `${SUPABASE_URL.replace(/\/+$/, '')}/rest/v1`,
    headers: {
        apikey: SUPABASE_ANON_KEY,
        Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
        'Content-Type': 'application/json',
    },
    timeout: 12000,
});

const toArrayImages = (value: unknown): string[] => {
    if (Array.isArray(value)) {
        return value.filter((item) => typeof item === 'string') as string[];
    }

    if (typeof value === 'string') {
        try {
            const parsed = JSON.parse(value);
            return Array.isArray(parsed) ? parsed.filter((item) => typeof item === 'string') as string[] : [];
        } catch {
            return value.trim() ? [value.trim()] : [];
        }
    }

    return [];
};

const normalizeProducts = (rows: any[]): any[] => rows.map((row) => ({
    ...row,
    images: toArrayImages(row?.images),
}));

const wrapPaginated = (rows: any[], total: number, perPage: number, page: number) => {
    const lastPage = Math.max(1, Math.ceil((total || 0) / perPage));

    return {
        data: {
            message: 'Products retrieved successfully',
            data: {
                data: rows,
                total,
                per_page: perPage,
                current_page: page,
                last_page: lastPage,
            },
        },
    };
};

const parseTotalFromContentRange = (contentRange?: string): number => {
    if (!contentRange || !contentRange.includes('/')) {
        return 0;
    }

    const totalRaw = contentRange.split('/')[1];
    const parsed = Number(totalRaw);
    return Number.isFinite(parsed) ? parsed : 0;
};

const buildProductsQuery = (params?: ProductFiltersParams): string => {
    const query = new URLSearchParams();
    query.set('select', '*,category:categories(*)');
    query.set('is_active', 'eq.true');

    const search = String(params?.search || '').trim();
    if (search) {
        const escaped = search.replace(/,/g, ' ');
        query.set('or', `(name.ilike.*${escaped}*,brand.ilike.*${escaped}*,description.ilike.*${escaped}*,vehicle_compatibility.ilike.*${escaped}*)`);
    }

    const categoryId = String(params?.category_id || params?.category || '').trim();
    if (categoryId) {
        query.set('category_id', `eq.${categoryId}`);
    }

    const brand = String(params?.brand || '').trim();
    if (brand) {
        query.set('brand', `ilike.*${brand.replace(/,/g, ' ')}*`);
    }

    const vehicleCompatibility = String((params as any)?.vehicle_compatibility || '').trim();
    if (vehicleCompatibility) {
        query.set('vehicle_compatibility', `ilike.*${vehicleCompatibility.replace(/,/g, ' ')}*`);
    }

    if ((params as any)?.price_min !== undefined && (params as any)?.price_min !== '') {
        query.set('price', `gte.${Number((params as any).price_min)}`);
    }

    if ((params as any)?.price_max !== undefined && (params as any)?.price_max !== '') {
        query.append('price', `lte.${Number((params as any).price_max)}`);
    }

    const allowedSortBy = new Set(['created_at', 'price', 'name', 'stock']);
    const sortBy = allowedSortBy.has(String((params as any)?.sort_by || '')) ? String((params as any).sort_by) : 'created_at';
    const sortOrder = String((params as any)?.sort_order || 'desc') === 'asc' ? 'asc' : 'desc';
    query.set('order', `${sortBy}.${sortOrder}`);

    const perPage = Math.max(1, Math.min(1000, Number((params as any)?.per_page || 24)));
    const page = Math.max(1, Number((params as any)?.page || 1));
    const offset = (page - 1) * perPage;
    query.set('limit', String(perPage));
    query.set('offset', String(offset));

    return query.toString();
};

const shouldFallback = (error: any): boolean => {
    const status = error?.response?.status;
    return status >= 500 || status === 0 || !status;
};

export const productService = {
    getAll: async (params?: ProductFiltersParams, config?: AxiosRequestConfig) => {
        try {
            return await api.get('/products', { params, ...config });
        } catch (error) {
            if (!CAN_USE_SUPABASE || !shouldFallback(error)) {
                throw error;
            }

            const query = buildProductsQuery(params);
            const perPage = Math.max(1, Math.min(1000, Number((params as any)?.per_page || 24)));
            const page = Math.max(1, Number((params as any)?.page || 1));
            const res = await supabaseRest.get(`/products?${query}`, {
                headers: { Prefer: 'count=exact' },
            });

            const rows = normalizeProducts(Array.isArray(res.data) ? res.data : []);
            const total = parseTotalFromContentRange(String(res.headers?.['content-range'] || '')) || rows.length;

            return wrapPaginated(rows, total, perPage, page);
        }
    },
    
    getById: async (id: string | number, config?: AxiosRequestConfig) => {
        try {
            return await api.get(`/products/${id}`, config);
        } catch (error) {
            if (!CAN_USE_SUPABASE || !shouldFallback(error)) {
                throw error;
            }

            const query = new URLSearchParams();
            query.set('select', '*,category:categories(*)');

            const rawId = String(id).trim();
            if (/^\d+$/.test(rawId)) {
                query.set('or', `(id.eq.${rawId},slug.eq.${rawId})`);
            } else {
                query.set('slug', `eq.${rawId}`);
            }

            query.set('limit', '1');
            const res = await supabaseRest.get(`/products?${query.toString()}`);
            const rows = normalizeProducts(Array.isArray(res.data) ? res.data : []);
            const product = rows[0] || null;

            if (!product) {
                throw error;
            }

            return {
                data: {
                    message: 'Product retrieved successfully',
                    data: product,
                },
            };
        }
    },
    
    getFeatured: async (config?: AxiosRequestConfig) => {
        try {
            return await api.get('/products/featured', config);
        } catch (error) {
            if (!CAN_USE_SUPABASE || !shouldFallback(error)) {
                throw error;
            }

            const res = await supabaseRest.get('/products?select=*,category:categories(*)&is_active=eq.true&order=created_at.desc&limit=12');
            const rows = normalizeProducts(Array.isArray(res.data) ? res.data : []);

            return {
                data: {
                    message: 'Featured products retrieved successfully',
                    data: rows,
                },
            };
        }
    },

    getHotDeals: async (config?: AxiosRequestConfig) => {
        try {
            return await api.get('/products/hot-deals', config);
        } catch (error) {
            if (!CAN_USE_SUPABASE || !shouldFallback(error)) {
                throw error;
            }

            const res = await supabaseRest.get('/products?select=*,category:categories(*)&is_active=eq.true&is_hot_deal=eq.true&order=created_at.desc&limit=12');
            const rows = normalizeProducts(Array.isArray(res.data) ? res.data : []);

            return {
                data: {
                    message: 'Hot deal products retrieved successfully',
                    data: rows,
                },
            };
        }
    },

    getPremium: async (config?: AxiosRequestConfig) => {
        try {
            return await api.get('/products/premium', config);
        } catch (error) {
            if (!CAN_USE_SUPABASE || !shouldFallback(error)) {
                throw error;
            }

            const res = await supabaseRest.get('/products?select=*,category:categories(*)&is_active=eq.true&is_premium=eq.true&order=created_at.desc&limit=12');
            const rows = normalizeProducts(Array.isArray(res.data) ? res.data : []);

            return {
                data: {
                    message: 'Premium products retrieved successfully',
                    data: rows,
                },
            };
        }
    },
    
    getByCategory: async (categoryId: string | number, params?: ProductFiltersParams, config?: AxiosRequestConfig) => {
        try {
            return await api.get(`/products/category/${categoryId}`, { params, ...config });
        } catch (error) {
            if (!CAN_USE_SUPABASE || !shouldFallback(error)) {
                throw error;
            }

            const query = new URLSearchParams();
            query.set('select', '*,category:categories(*)');
            query.set('category_id', `eq.${categoryId}`);
            query.set('is_active', 'eq.true');

            const perPage = Math.max(1, Math.min(1000, Number((params as any)?.per_page || 24)));
            const page = Math.max(1, Number((params as any)?.page || 1));
            const offset = (page - 1) * perPage;
            query.set('order', 'created_at.desc');
            query.set('limit', String(perPage));
            query.set('offset', String(offset));

            const res = await supabaseRest.get(`/products?${query.toString()}`, {
                headers: { Prefer: 'count=exact' },
            });
            const rows = normalizeProducts(Array.isArray(res.data) ? res.data : []);
            const total = parseTotalFromContentRange(String(res.headers?.['content-range'] || '')) || rows.length;

            return {
                data: {
                    message: 'Products retrieved successfully',
                    data: {
                        category: rows[0]?.category || null,
                        data: rows,
                        total,
                        per_page: perPage,
                        current_page: page,
                        last_page: Math.max(1, Math.ceil(total / perPage)),
                    },
                },
            };
        }
    },
    
    checkStock: async (id: string | number, config?: AxiosRequestConfig) => {
        try {
            return await api.get(`/products/${id}/stock`, config);
        } catch (error) {
            if (!CAN_USE_SUPABASE || !shouldFallback(error)) {
                throw error;
            }

            const res = await productService.getById(id, config);
            const product = (res as any)?.data?.data;
            const stock = Number(product?.stock || 0);

            return {
                data: {
                    message: 'Stock checked successfully',
                    data: {
                        product_id: product?.id,
                        stock,
                        available: stock > 0,
                        low_stock: stock > 0 && stock <= 5,
                    },
                },
            };
        }
    },
    
    search: async (query: string, config?: AxiosRequestConfig) =>
        productService.getAll({ search: query }, config),
};

export default productService;
